import{_ as o,C as n,o as l,c as s,E as i,w as e,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const p=JSON.parse('{"title":"Moving to Slovakia","description":"Immigration pathways and relocation guide for Slovakia","frontmatter":{"layout":"doc","title":"Moving to Slovakia","description":"Immigration pathways and relocation guide for Slovakia"},"headers":[],"relativePath":"europe/slovakia/moving-there.md","filePath":"europe/slovakia/moving-there.md","lastUpdated":null}'),h={name:"europe/slovakia/moving-there.md"};function u(c,t,g,m,f,v){const a=n("Badge");return l(),s("div",null,[i(a,{variant:"green"},{default:e(()=>[...t[0]||(t[0]=[r("EU: Free Movement",-1)])]),_:1}),i(a,{variant:"yellow"},{default:e(()=>[...t[1]||(t[1]=[r("Non-EU: Work Visa",-1)])]),_:1}),i(a,{variant:"yellow"},{default:e(()=>[...t[2]||(t[2]=[r("No Specific DN Visa",-1)])]),_:1}),t[3]||(t[3]=d('<h1 id="moving-to-slovakia" tabindex="-1">Moving to Slovakia <a class="header-anchor" href="#moving-to-slovakia" aria-label="Permalink to &quot;Moving to Slovakia&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><h3 id="eea-eu-citizens" tabindex="-1">EEA/EU Citizens <a class="header-anchor" href="#eea-eu-citizens" aria-label="Permalink to &quot;EEA/EU Citizens&quot;">​</a></h3><ul><li><strong>Free movement rights</strong> — no visa required</li><li><strong>Up to 3 months</strong>: No registration needed</li><li><strong>Over 3 months</strong>: Register with the Foreign Police (Cudzinecká polícia)</li><li><strong>Right to work</strong>: Automatic</li><li><strong>Residence registration</strong>: Required at the municipality</li></ul><h3 id="uk-citizens-post-brexit" tabindex="-1">UK Citizens (Post-Brexit) <a class="header-anchor" href="#uk-citizens-post-brexit" aria-label="Permalink to &quot;UK Citizens (Post-Brexit)&quot;">​</a></h3><ul><li><strong>Schengen Area</strong>: Visa-free for up to 90 days in any 180-day period</li><li><strong>Long-term residency</strong>: Requires a residence permit: <ul><li>Work permit (job offer from Slovak employer)</li><li>Student visa (enrollment at Slovak university)</li><li>Family reunification</li><li>Slovak Startup Visa</li></ul></li></ul><h3 id="third-country-nationals" tabindex="-1">Third-Country Nationals <a class="header-anchor" href="#third-country-nationals" aria-label="Permalink to &quot;Third-Country Nationals&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visa Type</th><th>Requirements</th><th>Duration</th></tr></thead><tbody><tr><td>Work Permit</td><td>Job offer from Slovak employer</td><td>Up to 2 years, renewable</td></tr><tr><td>Student Visa</td><td>Enrollment at accredited institution</td><td>Duration of studies</td></tr><tr><td>Family Reunification</td><td>Family ties to Slovak resident</td><td>Tied to sponsor&#39;s status</td></tr><tr><td>EU Blue Card</td><td>Highly skilled (salary ~€30,000+/year)</td><td>Up to 4 years</td></tr><tr><td>Startup Visa</td><td>Innovative business, approved by Slovak Investment Agency</td><td>Up to 2 years</td></tr></tbody></table><h2 id="digital-nomad-remote-work" tabindex="-1">Digital Nomad / Remote Work <a class="header-anchor" href="#digital-nomad-remote-work" aria-label="Permalink to &quot;Digital Nomad / Remote Work&quot;">​</a></h2><p>Slovakia does <strong>not have a dedicated digital nomad visa</strong>. Options:</p><ul><li><strong>Work visa</strong> if employed by a Slovak company</li><li><strong>Tourist visa</strong> for up to 90 days (no work permitted)</li><li><strong>Startup visa</strong> for entrepreneurs</li><li>Some remote workers use the <strong>short-term work visa</strong> for specific projects</li></ul><h2 id="moving-checklist" tabindex="-1">Moving Checklist <a class="header-anchor" href="#moving-checklist" aria-label="Permalink to &quot;Moving Checklist&quot;">​</a></h2><h3 id="before-moving" tabindex="-1">Before Moving <a class="header-anchor" href="#before-moving" aria-label="Permalink to &quot;Before Moving&quot;">​</a></h3><ul><li>[ ] <strong>Passport</strong>: Valid for duration of stay</li><li>[ ] <strong>Visa</strong>: Apply 2-3 months in advance (non-EU)</li><li>[ ] <strong>Healthcare</strong>: Private health insurance initially; register with VšZP after residency</li><li>[ ] <strong>HRT</strong>: Get 6-month supply and doctor&#39;s letter (translated to Slovak)</li><li>[ ] <strong>Banking</strong>: Consider Slovenská sporiteľňa, Tatra banka, or Revolut</li><li>[ ] <strong>Housing</strong>: Research rental market (nehnutelnosti.sk, topreality.sk)</li><li>[ ] <strong>Language</strong>: Slovak essential for daily life</li><li>[ ] <strong>Document translation</strong>: Official Slovak translations needed</li></ul><h3 id="after-arrival" tabindex="-1">After Arrival <a class="header-anchor" href="#after-arrival" aria-label="Permalink to &quot;After Arrival&quot;">​</a></h3><ul><li>[ ] Register with Foreign Police (non-EU) or municipality (EU)</li><li>[ ] Obtain Slovak ID number (Rodné číslo) — essential for all services</li><li>[ ] Register with VšZP (General Health Insurance Company)</li><li>[ ] Open local bank account</li><li>[ ] Get local SIM card (Orange, Telekom, O2)</li><li>[ ] Connect with LGBTQ+ community (Iniciatíva Inakosť, Proti Prúdu)</li><li>[ ] Register with Bratislava psychiatric clinic for trans healthcare</li></ul><h2 id="practical-information" tabindex="-1">Practical Information <a class="header-anchor" href="#practical-information" aria-label="Permalink to &quot;Practical Information&quot;">​</a></h2><h3 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h3><ul><li><strong>Low to moderate</strong> — affordable EU destination</li><li>Monthly rent (1-bed): €400-750 (Bratislava), €300-500 (Košice), €250-400 (Žilina)</li><li>Monthly groceries: €200-350</li><li>Public transport: €25-35/month (Bratislava)</li><li>Dining out: €7-14 per meal</li></ul><h3 id="best-cities-for-lgbtq-community" tabindex="-1">Best Cities for LGBTQ+ Community <a class="header-anchor" href="#best-cities-for-lgbtq-community" aria-label="Permalink to &quot;Best Cities for LGBTQ+ Community&quot;">​</a></h3><table tabindex="0"><thead><tr><th>City</th><th>LGBTQ+ Scene</th><th>Trans Healthcare</th></tr></thead><tbody><tr><td><strong>Bratislava</strong></td><td>Small but active</td><td>Only real option</td></tr><tr><td><strong>Košice</strong></td><td>Very limited</td><td>None</td></tr><tr><td><strong>Žilina</strong></td><td>Minimal</td><td>None</td></tr></tbody></table><h3 id="climate" tabindex="-1">Climate <a class="header-anchor" href="#climate" aria-label="Permalink to &quot;Climate&quot;">​</a></h3><ul><li><strong>Winters</strong>: Cold (-5°C to -10°C), snow common in mountains</li><li><strong>Summers</strong>: Warm (20-30°C)</li><li><strong>Best time to arrive</strong>: Spring or early autumn</li></ul><h3 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h3><ul><li>Official language: Slovak (West Slavic, similar to Czech)</li><li>English: Moderate in Bratislava, limited elsewhere</li><li>Czech: Widely understood due to historical ties</li><li>German: Somewhat understood in western areas</li><li>Slovak is essential for daily life and bureaucracy</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.minv.sk/?cudzinecka-policia" target="_blank" rel="noreferrer">Foreign Police (Cudzinecká polícia)</a></li><li><a href="https://www.vszp.sk/" target="_blank" rel="noreferrer">VšZP (General Health Insurance Company)</a></li><li><a href="https://www.inakost.sk/" target="_blank" rel="noreferrer">Iniciatíva Inakosť (LGBTQ+ Organization)</a></li><li><a href="https://www.protiprudu.sk/" target="_blank" rel="noreferrer">Proti Prúdu (Trans Organization)</a></li><li><a href="https://www.nehnutelnosti.sk/" target="_blank" rel="noreferrer">Nehnutelnosti.sk (housing)</a></li></ul>',27))])}const b=o(h,[["render",u]]);export{p as __pageData,b as default};
